import json
import pathlib
import requests

DEFAULT_REQUEST = {
  "geometry": {
    "nominal_diameter_mm": 50.0,
    "hub_outer_diameter_mm": 90.0,
    "contact_length_mm": 30.0,
    "fit_code": "H7/s6",
    "shaft_roughness_um": 2.0,
    "bore_roughness_um": 2.0
  },
  "materials": {
    "shaft_elastic_modulus_gpa": 210.0,
    "hub_elastic_modulus_gpa": 170.0,
    "shaft_poisson_ratio": 0.3,
    "hub_poisson_ratio": 0.29,
    "shaft_yield_strength_mpa": 550.0,
    "hub_yield_strength_mpa": 320.0,
    "shaft_thermal_expansion": 1.15e-05,
    "hub_thermal_expansion": 1.1e-05
  },
  "operating": {
    "transmitted_torque_nm": 700.0,
    "axial_force_n": 10000.0,
    "working_temperature_c": 120.0,
    "assembly_temperature_c": 20.0,
    "desired_installation_clearance_um": 30.0,
    "press_friction_coefficient": 0.12,
    "service_friction_coefficient": 0.15,
    "equipment_force_limit_kn": 35.0
  }
}


def _strip_code_fence(text):
    value = str(text or "").strip()
    if value.startswith("```"):
        parts = value.split("\n")
        if parts:
            parts = parts[1:]
        if parts and parts[-1].strip() == "```":
            parts = parts[:-1]
        value = "\n".join(parts).strip()
    return value


def _load_request():
    request_text = _strip_code_fence(globals().get("input_text", ""))
    input_files = globals().get("input_files", []) or []
    if not request_text:
        for raw_path in input_files:
            path = pathlib.Path(str(raw_path))
            if not path.exists() or path.suffix.lower() != ".json":
                continue
            for encoding in ("utf-8-sig", "utf-8", "gbk"):
                try:
                    request_text = path.read_text(encoding=encoding).strip()
                    break
                except UnicodeDecodeError:
                    continue
            if request_text:
                break
    if not request_text:
        return DEFAULT_REQUEST
    return json.loads(request_text)


def _parse_json(raw_text):
    text = str(raw_text or "").strip()
    if not text:
        return None
    return json.loads(text)


def _headers():
    headers = {}
    parsed = _parse_json(globals().get("headers_json", ""))
    if parsed:
        headers.update({str(key): str(value) for key, value in parsed.items()})
    api_key = str(globals().get("api_key", "") or "").strip()
    header_name = str(globals().get("api_key_header", "X-API-Key") or "X-API-Key").strip()
    if api_key:
        if header_name.lower() == "authorization" and not api_key.lower().startswith("bearer "):
            headers[header_name] = f"Bearer {api_key}"
        else:
            headers[header_name] = api_key
    return headers


def _merge_config(payload):
    config_override = dict(_parse_json(globals().get("config_json", "")) or {})
    llm_enabled = str(globals().get("llm_enabled", "false") or "false").strip().lower() in ("1", "true", "yes", "on", "enabled")
    llm_payload = {
        "enabled": llm_enabled,
        "provider": str(globals().get("llm_provider", "") or "").strip(),
        "model": str(globals().get("llm_model", "") or "").strip(),
        "api_base_url": str(globals().get("llm_api_base_url", "") or "").strip(),
        "api_key": str(globals().get("llm_api_key", "") or "").strip(),
        "temperature": float(globals().get("llm_temperature", "0.0") or 0.0),
        "max_tokens": int(float(globals().get("llm_max_tokens", "700") or 700)),
    }
    if llm_enabled or llm_payload["model"] or llm_payload["api_key"]:
        merged_llm = dict(config_override.get("llm") or {})
        merged_llm.update({key: value for key, value in llm_payload.items() if value != ""})
        config_override["llm"] = merged_llm
    if not config_override:
        return payload
    merged = dict(payload.get("config") or {})
    merged.update(config_override)
    next_payload = dict(payload)
    next_payload["config"] = merged
    return next_payload


operation = str(globals().get("operation", "multiagent_run") or "multiagent_run").strip().lower()
thread_id = str(globals().get("thread_id", "") or "").strip()
approval_decision = str(globals().get("approval_decision", "approve") or "approve").strip().lower()
approval_comment = str(globals().get("approval_comment", "") or "").strip()
api_url = str(globals().get("api_url", "http://127.0.0.1:8010") or "http://127.0.0.1:8010").rstrip("/")
timeout_seconds = float(globals().get("timeout_seconds", "300") or 300)
headers = _headers()

if operation == "analyze":
    request_payload = _merge_config(_load_request())
    response = requests.post(f"{api_url}/analyze", json=request_payload, headers=headers, timeout=timeout_seconds)
elif operation == "multiagent_run":
    request_payload = _merge_config(_load_request())
    if thread_id:
        request_payload = dict(request_payload)
        request_payload["thread_id"] = thread_id
    response = requests.post(f"{api_url}/multiagent/runs", json=request_payload, headers=headers, timeout=timeout_seconds)
elif operation == "multiagent_resume":
    if not thread_id:
        raise ValueError("thread_id is required for multiagent_resume")
    request_payload = {
        "decision": approval_decision,
        "comment": approval_comment,
    }
    config_override = _parse_json(globals().get("config_json", ""))
    if config_override:
        request_payload["config"] = config_override
    response = requests.post(
        f"{api_url}/multiagent/runs/{thread_id}/resume",
        json=request_payload,
        headers=headers,
        timeout=timeout_seconds,
    )
elif operation == "multiagent_state":
    if not thread_id:
        raise ValueError("thread_id is required for multiagent_state")
    params = {}
    config_override = _parse_json(globals().get("config_json", ""))
    if config_override and config_override.get("checkpoint_db_path"):
        params["checkpoint_db_path"] = config_override["checkpoint_db_path"]
    response = requests.get(
        f"{api_url}/multiagent/runs/{thread_id}",
        params=params,
        headers=headers,
        timeout=timeout_seconds,
    )
else:
    raise ValueError("Unsupported operation. Use analyze, multiagent_run, multiagent_resume, or multiagent_state.")

response.raise_for_status()
print(json.dumps(response.json(), ensure_ascii=False, indent=2))
